const body = $input.first().json.body || {};
const headers = $input.first().json.headers || {};

if (headers['x-gpmd-secret'] !== 'GPMD_WEBHOOK_SECRET') {
  return [{ json: { ok: 'false', error: 'Unauthorized' } }];
}

const { phone, estado, nombre, codigo, razon } = body;
if (!phone || !estado) {
  return [{ json: { ok: 'false', error: 'phone y estado requeridos' } }];
}

let mensaje = '';
const razones_label = {
  foto_ilegible: 'la foto no era legible',
  fuera_periodo: 'la factura está fuera del período de participación',
  producto_no_participante: 'el producto no es participante',
  establecimiento_no_participante: 'el establecimiento no es participante',
  factura_duplicada: 'la factura ya fue registrada anteriormente',
  valor_insuficiente: 'el valor no cumple el mínimo requerido',
  otro: 'ver detalle adjunto',
};

if (estado === 'aprobado') {
  mensaje = `✅ *¡Felicitaciones, ${nombre || 'participante'}!*\n\n`
    + `Tu registro en el *Gran Premio Mobil Delvac 2026* ha sido *APROBADO*.\n\n`
    + `🏁 Código de preregistro: *${codigo || '—'}*\n\n`
    + `Recuerda presentarte en el horario asignado con los documentos originales.\n`
    + `¡Mucha suerte en la pista! 🚛💨`;
} else if (estado === 'rechazado') {
  const razonLabel = razones_label[razon] || razon || 'revisar condiciones';
  mensaje = `❌ *Hola ${nombre || 'participante'},*\n\n`
    + `Lamentablemente tu factura no pudo ser aceptada porque ${razonLabel}.\n\n`
    + `Si tienes dudas, responde este mensaje y un asesor te ayudará en menos de 24 horas.`;
} else if (estado === 'en_revision') {
  mensaje = `⏳ *Hola ${nombre || 'participante'},*\n\n`
    + `Recibimos tu factura y la estamos revisando manualmente.\n`
    + `Te notificaremos en un máximo de 24 horas con el resultado.`;
}

return [{ json: { phone, mensaje } }];
